parameters.jsCode:
const error = $input.first().json;

const execution = error.execution || {};
const workflow = error.workflow || {};
const lastNode = execution.lastNodeExecuted || 'Unknown';

let errorMessage = 'Unknown error';
let inputData = '';

try {
  if (execution.error?.message) {
    errorMessage = execution.error.message;
  } else if (typeof error.message === 'string') {
    errorMessage = error.message;
  }
} catch (e) {
  errorMessage = JSON.stringify(error).substring(0, 1000);
}

try {
  const nodeData = execution.data?.resultData?.runData?.[lastNode];
  if (nodeData && nodeData[0]?.data?.main?.[0]?.[0]) {
    inputData = JSON.stringify(nodeData[0].data.main[0][0].json).substring(0, 2000);
  }
} catch (e) {
  inputData = 'Could not extract input data';
}

return [{
  json: {
    workflow_name: workflow.name || 'Unknown',
    workflow_id: workflow.id || '',
    node_name: lastNode,
    error_message: errorMessage,
    execution_id: execution.id || '',
    timestamp: new Date().toISOString(),
    severity: 'Error',
    input_data: inputData
  }
}];

